INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-00024', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關白化症（Albinism）病童之敘述，下列何者正確？', '["白化症的病因是由於黑色素細胞內的酪氨酸酶（tyrosinase）過多堆積造成", "病童全身皮膚、毛髮、眼睛缺乏黑色素，虹膜也因缺乏黑色素而呈現淡色", "病童常有屈光不正及外斜視（exotropia），但少見眼球震顫（nystagmus）", "針對白化症治療，除利用物理方式如太陽眼鏡或帽子遮光之外，可以使用藥物治療，使黑色素細胞增生 改善病況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00025', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力重建與照護，有關多方專業團隊之敘述，下列何者錯誤？', '["有許多人和組織為低視力視覺損傷者提供各種商品和資源服務", "驗光師只需知道自己的專業即可，無需多了解相關輔助產品或其他轉介資源服務", "每個專業團體成員，需對自己可做出的貢獻度清楚以及其他專業的知識有充分了解", "不同專業間彼此的轉介是重要的，這包含驗光師、眼科醫師、社會工作師、重建教師、職能治療師、定 向行動專家……等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00026', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '感染帶狀皰疹時，若出現以下何種表徵，較易侵犯到眼睛？', '["Huntingtonsign", "Munsonsign", "Hutchinsonsign", "Rizzuti''ssign"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00027', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '關於圓錐角膜之敘述，下列何者錯誤？', '["疾病初期視力模糊是唯一症狀", "和許多疾病皆有相關，如唐氏症、異位性皮膚炎、視網膜色素病變、馬方氏症和Ehlers-Danlos氏症候群等", "進程緩慢，屈光異常造成的症狀通常始於20多歲，於40多歲趨於穩定", "疾病徵象包含後彈力層中央的線性皺褶（Vogt’slines）、棕綠色環（Kayser-Fleischerrings）及Munson 氏 徵象"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00028', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '乾眼症之診斷依據，不包括下列何者？', '["家族疾病史", "淚液分泌試驗", "角膜結膜染色試驗", "臨床症狀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00029', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關結膜炎之敘述，下列何者錯誤？', '["共通的症狀常為流淚、砂礫感、刺痛、灼熱", "病毒感染引起的較常為膿性（purulent）分泌物", "過敏性結膜炎較常為粘液性（mucoid）分泌物", "砂眼則較常為粘液膿性（mucopurulent）分泌物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00030', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關因長期使用類固醇所引發的白內障之敘述，下列何者錯誤？', '["後囊型（posteriorsubcapsular）最為常見", "各種劑型的類固醇都有可能引發白內障", "病患通常在強烈陽光下的視覺品質比在室內還差", "病患在看遠時會比看近時更容易感到視力不良"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00031', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '根據葡萄膜炎命名標準化工作小組（StandardizationofUveitisNomenclatureWorkingGroup）定義的葡萄膜 炎分類，當眼球發炎最主要同時影響玻璃體和平坦部（ParsPlana），則會被歸類為何種葡萄膜炎？', '["前葡萄膜炎", "中葡萄膜炎", "後葡萄膜炎", "全葡萄膜炎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00032', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '葡萄膜炎患者眼底可見玻璃體混濁，透過玻璃體炎可觀察到白色視網膜炎性病灶，很像霧裡的車頭燈 （headlightinthefog），患者很可能是下列那種疾病引起？', '["巨細胞病毒引發的視網膜炎（cytomegalovirusretinitis）", "弓漿蟲感染的脈絡膜視網膜炎（oculartoxoplasmosis）", "僵直性脊椎炎引起的前葡萄膜炎", "韓瑟勒巴通氏菌引起的貓抓病（cat-scratchdisease）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00033', 'optometrist', 'optometrist-moex-114-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關先天性弓漿蟲症之敘述，下列何者正確？', '["在妊娠的第二期（secondtrimester）發生感染", "母體一旦感染弓漿蟲，90%的新生兒都會發生垂直感染", "在視網膜後極，以後葡萄膜炎及局部視網膜脈絡膜炎最為常見", "採結膜下注射類固醇，可以有效減緩後葡萄膜炎的程度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "5093f492e448", "answer_pdf_sha1": "f33d754e2a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
